import React, { useState, useEffect } from 'react';
import { api } from '../services/api';
import BlockchainDashboard from '../components/Blockchain/BlockchainDashboard';
import PolicyManager from '../components/Blockchain/PolicyManager';
import IncidentTracker from '../components/Blockchain/IncidentTracker';

function Blockchain() {
  const [connected, setConnected] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    testConnection();
  }, []);

  const testConnection = async () => {
    try {
      await api.health();
      setConnected(true);
      console.log(' Backend connecté');
    } catch (err) {
      console.log(' Backend hors ligne, mode démo');
      setConnected(true); // Mode démo
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div style={{background:'#1A2332',borderRadius:'12px',padding:'60px 40px',textAlign:'center',border:'1px solid #2A3A4A'}}>
        <div style={{fontSize:'40px',marginBottom:'20px'}}></div>
        <h2 style={{color:'#FFFFFF'}}>Chargement...</h2>
      </div>
    );
  }

  return (
    <div>
      {/* Header */}
      <div style={{
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        marginBottom: '24px',
        padding: '16px 20px',
        background: '#1A2332',
        borderRadius: '12px',
        border: '1px solid #2A3A4A'
      }}>
        <div>
          <h1 style={{color:'#FFFFFF',fontSize:'24px',margin:0}}> Blockchain Module</h1>
          <p style={{color:'#94A3B8',margin:'4px 0 0 0',fontSize:'14px'}}>
            Interface de gestion blockchain sécurisée
          </p>
        </div>
        <div style={{
          padding:'6px 16px',
          borderRadius:'20px',
          background: connected ? 'rgba(16,185,129,0.2)' : 'rgba(239,68,68,0.2)',
          border: connected ? '1px solid rgba(16,185,129,0.3)' : '1px solid rgba(239,68,68,0.3)'
        }}>
          <span style={{color: connected ? '#10B981' : '#EF4444'}}>
            {connected ? ' Connecté' : ' Déconnecté'}
          </span>
        </div>
      </div>

      {/* Dashboard */}
      <div style={{marginBottom:'24px'}}>
        <BlockchainDashboard />
      </div>

      {/* Actions */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: '1fr 1fr',
        gap: '20px'
      }}>
        <PolicyManager />
        <IncidentTracker />
      </div>
    </div>
  );
}

export default Blockchain;
